module.render:
const body = sections[0] ? sections[0].trim() : '';
const color = (args.color && String(args.color).trim()) || 'var(--accent-color)';
const fill = String(args.fill) === 'true';
const fs = { small: '0.7em', medium: '0.8em', large: '0.95em' }[String(args.size || 'medium').toLowerCase()] || '0.8em';
const rad = { pill: '9999px', rounded: '6px', square: '2px' }[String(args.shape || 'pill').toLowerCase()] || '9999px';
let style = 'font-size: ' + fs + '; border-radius: ' + rad + '; border-color: ' + color + '; ';
style += fill ? ('color: #fff; background-color: ' + color + ';') : ('color: ' + color + '; background-color: transparent;');
return '<span class="mdp-mod-label" style="' + style + '">' + body + '</span>';
